I just encountered exactly same problem... 
Here are my codes
`
import luigi

paras = {}

outfile = {'outfile': 'word.txt'}

paras['SimpleTask'] = outfile


class SimpleTask(luigi.Task):
    """
    SimpleTask prints Hello World!.
    """
    my_paras = luigi.DictParameter()

    def output(self):
        st_para = self.my_paras['SimpleTask']
        tar_file = st_para['outfile']
        return luigi.LocalTarget(tar_file)

    def run(self):
        words = [
            'apple',
            'banana',
            'grapefruit'
        ]
        with self.output().open('w') as f:
