class DecoratedTask(luigi.Task):
    """
    DecoratedTask depends on the SimpleTask
    """

    def requires(self):
        return SimpleTask(my_paras=paras)

    def output(self):
        return luigi.LocalTarget('letter_counts.txt')

    def run(self):

        # read in file as list
        with self.input().open('r') as infile:
            words = infile.read().splitlines()

        # write each word to output file with its corresponding letter count
        with self.output().open('w') as outfile:
            for word in words:
                outfile.write(
                        '{word} | {letter_count}\n'.format(
                            word=word,
                            letter_count=len(word)
                            )
                        )


if __name__ == '__main__':
    luigi.run(["--local-scheduler"], main_task_cls=DecoratedTask)
